class BaseReporter {
    resolvedConfig;
    constructor(resolvedConfig) {
        this.resolvedConfig = resolvedConfig;
    }
}

class FileView {
    #indent = 0;
    #lines = [];
    #messages = [];
    get hasErrors() {
        return this.#messages.length > 0;
    }
    addMessage(message) {
        this.#messages.push(message);
    }
    addTest(status, name) {
        this.#lines.push(testNameText(status, name, this.#indent));
    }
    beginDescribe(name) {
        this.#lines.push(describeNameText(name, this.#indent));
        this.#indent++;
    }
    clear() {
        this.#indent = 0;
        this.#lines = [];
        this.#messages = [];
    }
    endDescribe() {
        this.#indent--;
    }
    getMessages() {
        return this.#messages;
    }
    getViewText(options) {
        return fileViewText(this.#lines, options?.appendEmptyLine || this.hasErrors);
    }
}

class ListReporter extends BaseReporter {
    #fileCount = 0;
    #fileView = new FileView();
    #hasReportedAdds = false;
    #hasReportedError = false;
    #hasReportedUses = false;
    #isFileViewExpanded = false;
    get #isLastFile() {
        return this.#fileCount === 0;
    }
    on([event, payload]) {
        switch (event) {
            case "run:start":
                this.#isFileViewExpanded = payload.result.tasks.length === 1 && this.resolvedConfig.watch !== true;
                break;
            case "store:adds":
                OutputService.writeMessage(addsPackageText(payload.packageVersion, payload.packagePath));
                this.#hasReportedAdds = true;
                break;
            case "store:error":
                for (const diagnostic of payload.diagnostics) {
                    OutputService.writeError(diagnosticText(diagnostic));
                }
                break;
            case "target:start":
                this.#fileCount = payload.result.tasks.length;
                this.#hasReportedUses = false;
                break;
            case "project:uses":
                OutputService.writeMessage(usesCompilerText(payload.compilerVersion, payload.projectConfigFilePath, {
                    prependEmptyLine: this.#hasReportedUses && !this.#hasReportedAdds && !this.#hasReportedError,
                }));
                this.#hasReportedAdds = false;
                this.#hasReportedUses = true;
                break;
            case "project:error":
                for (const diagnostic of payload.diagnostics) {
                    OutputService.writeError(diagnosticText(diagnostic));
                }
                break;
            case "task:start":
                if (!environmentOptions.noInteractive) {
                    OutputService.writeMessage(taskStatusText(payload.result.status, payload.result.task));
                }
                this.#fileCount--;
                this.#hasReportedError = false;
                break;
            case "task:error":
            case "directive:error":
            case "collect:error":
                for (const diagnostic of payload.diagnostics) {
                    this.#fileView.addMessage(diagnosticText(diagnostic));
                }
                break;
            case "task:end":
                if (!environmentOptions.noInteractive) {
                    OutputService.eraseLastLine();
                }
                OutputService.writeMessage(taskStatusText(payload.result.status, payload.result.task));
                OutputService.writeMessage(this.#fileView.getViewText({ appendEmptyLine: this.#isLastFile }));
                if (this.#fileView.hasErrors) {
                    OutputService.writeError(this.#fileView.getMessages());
                    this.#hasReportedError = true;
                }
                this.#fileView.clear();
                break;
            case "describe:start":
                if (this.#isFileViewExpanded) {
                    this.#fileView.beginDescribe(payload.result.describe.name);
                }
                break;
            case "describe:end":
                if (this.#isFileViewExpanded) {
                    this.#fileView.endDescribe();
                }
                break;
            case "test:skip":
                if (this.#isFileViewExpanded) {
                    this.#fileView.addTest("skip", payload.result.test.name);
                }
                break;
            case "test:todo":
                if (this.#isFileViewExpanded) {
                    this.#fileView.addTest("todo", payload.result.test.name);
                }
                break;
            case "test:error":
                if (this.#isFileViewExpanded) {
                    this.#fileView.addTest("fail", payload.result.test.name);
                }
                for (const diagnostic of payload.diagnostics) {
                    this.#fileView.addMessage(diagnosticText(diagnostic));
                }
                break;
            case "test:fail":
                if (this.#isFileViewExpanded) {
                    this.#fileView.addTest("fail", payload.result.test.name);
                }
                break;
            case "test:pass":
                if (this.#isFileViewExpanded) {
                    this.#fileView.addTest("pass", payload.result.test.name);
                }
                break;
            case "expect:error":
            case "expect:fail":
                for (const diagnostic of payload.diagnostics) {
                    this.#fileView.addMessage(diagnosticText(diagnostic));
                }
                break;
        }
    }
}

class SetupReporter {
    on([event, payload]) {
        if (event === "store:adds") {
            OutputService.writeMessage(addsPackageText(payload.packageVersion, payload.packagePath));
            return;
        }
        if ("diagnostics" in payload) {
            for (const diagnostic of payload.diagnostics) {
                switch (diagnostic.category) {
                    case DiagnosticCategory.Error:
                        OutputService.writeError(diagnosticText(diagnostic));
                        break;
                    case DiagnosticCategory.Warning:
                        OutputService.writeWarning(diagnosticText(diagnostic));
                        break;
                }
            }
        }
    }
}

class SummaryReporter extends BaseReporter {
    on([event, payload]) {
        if (this.resolvedConfig.watch) {
            return;
        }
        if (event === "run:end") {
            OutputService.writeMessage(summaryText({
                duration: payload.result.timing.duration,
                expectCount: payload.result.expectCount,
                fileCount: payload.result.fileCount,
                targetCount: payload.result.targetCount,
                testCount: payload.result.testCount,
            }));
        }
    }
}

class WatchReporter extends BaseReporter {
    on([event, payload]) {
        switch (event) {
            case "run:start":
                OutputService.clearTerminal();
                break;
            case "run:end":
                OutputService.writeMessage(watchUsageText());
                break;
            case "watch:error":
                OutputService.clearTerminal();
                for (const diagnostic of payload.diagnostics) {
                    OutputService.writeError(diagnosticText(diagnostic));
                }
                OutputService.writeMessage(waitingForFileChangesText());
                break;
        }
    }
}

